var item = require('../items.json')
export default {
  name: 'new',
  data () {
    return {
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      items: item
    }
  },
  mounted () {
    const data = require('../items.json')
    this.items = data
    console.log(this.items)
  }
}
